from file_a import fetch_user
from file_b import get_username

def test_fetch():
    try:
        assert fetch_user(1)["name"]
    except UserNotFoundError as e:
        assert False, f"Unexpected exception: {e}"

def test_unknown():
    try:
        assert get_username(-1) == "unknown"
    except UserNotFoundError as e:
        assert False, f"Unexpected exception: {e}"

def test_user_not_found_fetch():
    try:
        fetch_user(99)
        assert False, "UserNotFoundError not raised"
    except UserNotFoundError as e:
        assert str(e) == "User with ID 99 not found."

def test_user_not_found_greet():
    try:
        greet(99)
        assert False, "UserNotFoundError not raised"
    except UserNotFoundError as e:
        assert str(e) == "User with ID 99 not found."
